/** Keep in sync with `APP_FOOTER_LEGAL_NAME` in `js/app.js`. */
export const FOOTER_LEGAL_NAME = "WERKDONE PTE LTD.";

/** Single copyright line — use inside `Footer` or where a minimal inline line is needed. */
export function FooterCopyrightLine({ className }: { className?: string }) {
  return (
    <div className={className}>
      Copyright © {new Date().getFullYear()} {FOOTER_LEGAL_NAME}
    </div>
  );
}

/**
 * Global app footer — compact band at the bottom of the shell.
 * Render once from App (outside scrolling main) so it stays at the viewport bottom.
 */
export function Footer() {
  return (
    <footer
      className="shrink-0 w-full bg-white text-[#808080] text-center text-xs leading-tight p-2 font-sans antialiased"
      role="contentinfo"
    >
      <FooterCopyrightLine />
      <p className="mt-1 text-[0.65rem] leading-tight text-[#808080]/85">
        Icons:{" "}
        <a
          href="https://www.flaticon.com/uicons"
          target="_blank"
          rel="noopener noreferrer"
          className="underline underline-offset-2 decoration-[#808080]/60 hover:decoration-[#808080]"
        >
          Uicons by Flaticon
        </a>
      </p>
    </footer>
  );
}
